VALUES
  ('optician-moex-02009', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者暫定度數為-10.25DS/-1.50DC×075，進行交叉圓柱鏡檢測散光度數時，調整減少負散光鏡片-0.50 D， 則受檢者度數應該調整為何？', '["-10.75DS/-1.00DC×075", "-10.50DS/-1.00DC×075", "-10.00DS/-1.00DC×075", "-9.75DS/-1.50DC×075"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02010', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關老花眼症狀的敘述，下列何者錯誤？', '["喜歡在昏暗的光線下閱讀", "習慣將書報移遠", "不自覺地將頭後仰", "視近物不能持久"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02011', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '近用視標有許多種標示文字大小方式。N標示法（N-notation）是現代電腦文書編輯及列表機常用的方式。 在40 cm的近用距離測量下，書籍常用的N12若換算成史耐倫等價視力（Snellen equivalent）相當於下列 何者？', '["20/20", "20/40", "20/60", "20/80"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02012', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用動態視網膜檢影鏡執行單眼評估方法（monocular estimation method, MEM）確認調節精準度。使用平 行光進行檢影時，受檢者眼睛的反射光為順動（with-movement），下列敘述何者正確？', '["受檢者有調節遲滯（lag of accommodation）的現象，需要加正鏡片來中和", "受檢者有調節遲滯的現象，需要加負鏡片來中和", "受檢者有調節過度或超前（lead of accommodation）的現象，需要加正鏡片來中和", "受檢者有調節過度或超前的現象，需要加負鏡片來中和"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02013', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列何種視力矯正方法可提供較大的視網膜影像，可是卻減少調節效率（accommodative efficiency）？', '["用一般眼鏡矯正近視", "用隱形眼鏡矯正近視", "用隱形眼鏡矯正遠視", "用一般眼鏡或隱形眼鏡矯正近視或遠視沒有差別"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02014', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關調節幅度的敘述，下列何者最不恰當？', '["可以是單眼，也可以是雙眼的測量", "最好在驗光後，以驗光之後的度數實施這項測驗", "最好使用史耐倫視力表0.1的視標大小當作測試的目標", "通常使用推近法（push-up），若對幼小患童無法了解「模糊點」，可以使用移遠法（pull-away）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02015', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '參考霍夫施泰特公式（Hofstetter''s formulas），一般40歲成人的平均調節幅度期望值約為何？', '["5.0 D", "5.5 D", "6.5 D", "8.0 D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02016', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關融像性交叉圓柱鏡（fused cross cylinder, FCC）檢測的敘述，下列何者錯誤？', '["此測試可以用來評估患者的調節精準度（accommodation accuracy）", "測量時將傑克森交叉圓柱鏡的紅點對準90度", "若患者的調節力不足，則垂直線比水平線來得清楚", "若水平線比垂直線清楚，則需加入正球面（plus）鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02017', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '依據調節幅度百分比與調節需求計算加入度的方法，除了調節幅度一半原則（half the amp in reserve）， 另有一派學者認為人類能持續維持的調節，占總調節幅度的三分之二。若有一患者屈光不正為遠視+1.50 D， 調節幅度為3.00 D ，工作距離為40 cm，則依據調節幅度三分之二原則，建議的近用處方為何？', '["+1.50 D", "+1.75 D", "+2.00 D", "+2.50 D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02018', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '假設有一患者屈光不正為近視-2.00 D，調節幅度為0 D，於近距離時的焦深（depth of focus）為±0.40 D。 在裸視狀況下，其眼前清晰視覺範圍（range of clear vision）應大約介於何者之間？', '["25 cm-45 cm", "30 cm-50 cm", "35 cm-55 cm", "40 cm-60 cm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
